from typing import List

class Solution:
    def majorityElement(self, nums: List[int]) -> List[int]:
        if not nums:
            return []

        # At most two elements can appear more than n/3 times.
        # Initialize two candidates and their counts.
        candidate1, count1 = 0, 0
        candidate2, count2 = 1, 0 # Initialize candidate2 to a different value to avoid conflict if candidate1 is chosen.

        # First pass: find potential candidates
        for num in nums:
            if num == candidate1:
                count1 += 1
            elif num == candidate2:
                count2 += 1
            elif count1 == 0:
                candidate1 = num
                count1 = 1
            elif count2 == 0:
                candidate2 = num
                count2 = 1
            else:
                count1 -= 1
                count2 -= 1

        # Second pass: verify the counts of the potential candidates
        # Reset counts for actual verification
        count1, count2 = 0, 0
        for num in nums:
            if num == candidate1:
                count1 += 1
            elif num == candidate2:
                count2 += 1

        result = []
        n = len(nums)
        threshold = n // 3

        if count1 > threshold:
            result.append(candidate1)
        if count2 > threshold:
            # Avoid adding the same element twice if candidate1 and candidate2 ended up being the same
            # (e.g., if there's only one majority element and the list is structured in a way that
            # both candidates converge to it, or if input is small).
            if not result or result[0] != candidate2:
                result.append(candidate2)

        return result
